  --sidebar-primary-foreground: hsl(210, 40%, 98%);
  --sidebar-accent: hsl(220, 13%, 15%);
  --sidebar-accent-foreground: hsl(220, 9%, 91%);
  --sidebar-border: hsl(220, 13%, 15%);
  --sidebar-ring: hsl(221, 83%, 53%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
  }

  html[dir="rtl"] {
    direction: rtl;
  }

  html[dir="rtl"] .sidebar {
    right: 0;
    left: auto;
  }

  html[dir="rtl"] .main-content {
    margin-right: 16rem;
    margin-left: 0;
  }
}

@layer components {
  .sidebar {
    @apply fixed left-0 top-16 h-[calc(100vh-4rem)] w-64 bg-sidebar border-r border-sidebar-border overflow-y-auto z-40 transition-transform duration-300 ease-in-out;
  }

  .main-content {
    @apply ml-64 pt-16 min-h-screen transition-all duration-300 ease-in-out;
  }

  .loading {
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent);
    background-size: 200px 100%;
    animation: loading 1.5s infinite;
  }
}

@layer utilities {
  @keyframes loading {
    0% { background-position: -200px 0; }
    100% { background-position: calc(200px + 100%) 0; }
  }

  /* Mobile responsive sidebar */
  @media (max-width: 768px) {
    .sidebar {
      @apply -translate-x-full;
    }

    html[dir="rtl"] .sidebar {
      @apply translate-x-full;
    }

    .sidebar.open {
      @apply translate-x-0;
    }

    .main-content {
      @apply ml-0;
    }

    html[dir="rtl"] .main-content {
      @apply mr-0;
    }
  }
}

