import { useState } from "react";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/hooks/use-auth";
import { useLanguage } from "@/components/language-provider";
import { formatInTimezone } from "@/lib/timezone";
import { Gavel, Bell, Menu, LogOut } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

interface HeaderProps {
  onSidebarToggle: () => void;
}

export function Header({ onSidebarToggle }: HeaderProps) {
  const { user, logoutMutation } = useAuth();
  const { language, setLanguage, t } = useLanguage();

  const handleLanguageToggle = (lang: "en" | "ar") => {
    setLanguage(lang);
    document.documentElement.setAttribute("lang", lang);
    document.documentElement.setAttribute("dir", lang === "ar" ? "rtl" : "ltr");
  };

  const handleLogout = () => {
    logoutMutation.mutate();
  };

  const getRoleDisplayName = (role: string) => {
    const roleMap = {
      admin: t('roles.admin', 'Administrator'),
      procurement_officer: t('roles.procurementOfficer', 'Procurement Officer'),
      bidder: t('roles.bidder', 'Bidder'),
    };
    return roleMap[role] || role;
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map(word => word.charAt(0))
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  return (
    <header className="bg-card border-b border-border px-4 lg:px-6 h-16 flex items-center justify-between fixed top-0 left-0 right-0 z-50">
      <div className="flex items-center gap-4">
        <Button
          variant="ghost"
          size="sm"
          className="lg:hidden"
          onClick={onSidebarToggle}
          data-testid="button-sidebar-toggle"
        >
          <Menu className="h-5 w-5" />
        </Button>

        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
            <Gavel className="w-5 h-5 text-primary-foreground" />
          </div>
          <div>
            <h1 className="text-lg font-semibold" data-testid="app-title">
              {t('app.title', 'NGO Procurement')}
            </h1>
            <p className="text-xs text-muted-foreground" data-testid="organization-name">
              {user?.organizationName || t('app.defaultOrg', 'Global Relief Foundation')}
            </p>
          </div>
        </div>
      </div>

      <div className="flex items-center gap-4">
        {/* Language Toggle */}
        <div className="flex items-center border border-border rounded-lg p-1">
          <Button
            variant={language === "en" ? "default" : "ghost"}
            size="sm"
            className="h-7 px-3 text-xs"
            onClick={() => handleLanguageToggle("en")}
            data-testid="button-language-en"
          >
            EN
          </Button>
          <Button
            variant={language === "ar" ? "default" : "ghost"}
            size="sm"
            className="h-7 px-3 text-xs"
            onClick={() => handleLanguageToggle("ar")}
            data-testid="button-language-ar"
          >
            العربية
          </Button>
        </div>

        {/* Notifications */}
        <Button
          variant="ghost"
          size="sm"
          className="relative"
          data-testid="button-notifications"
        >
          <Bell className="h-5 w-5" />
          <Badge className="absolute -top-1 -right-1 h-5 w-5 rounded-full p-0 flex items-center justify-center text-xs bg-destructive text-destructive-foreground">
            0
          </Badge>
        </Button>

        {/* Current Time */}
        <div className="hidden md:block text-sm text-muted-foreground" data-testid="current-time">
          {formatInTimezone(new Date(), user?.timezone || 'UTC')}
        </div>

        {/* User Menu */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" className="flex items-center gap-3 h-auto p-2" data-testid="button-user-menu">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-medium" data-testid="user-name">
                  {user?.username || 'User'}
                </p>
                <p className="text-xs text-muted-foreground" data-testid="user-role">
                  {getRoleDisplayName(user?.role || 'user')}
                </p>
              </div>
              <div className="w-8 h-8 bg-secondary rounded-full flex items-center justify-center">
                <span className="text-sm font-medium" data-testid="user-initials">
                  {getInitials(user?.username || 'User')}
                </span>
              </div>
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-56">
            <div className="px-2 py-1.5">
              <p className="text-sm font-medium">{user?.username}</p>
              <p className="text-xs text-muted-foreground">{user?.email}</p>
            </div>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={handleLogout} data-testid="button-logout">
              <LogOut className="w-4 h-4 mr-2" />
              {t('auth.logout', 'Logout')}
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </header>
  );
}

client/src/components/layout/main-layout.content:
import { useState } from "react";
import { Header } from "./header";
import { Sidebar } from "./sidebar";
import { useAuth } from "@/hooks/use-auth";
import { Redirect } from "wouter";

interface MainLayoutProps {
  children: React.ReactNode;
}

export function MainLayout({ children }: MainLayoutProps) {
  const { user, isLoading } = useAuth();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  const closeSidebar = () => {
    setSidebarOpen(false);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!user) {
    return <Redirect to="/auth" />;
  }

  return (
    <div className="min-h-screen bg-background">
      <Header onSidebarToggle={toggleSidebar} />
      <Sidebar isOpen={sidebarOpen} onClose={closeSidebar} />

      <main className="main-content p-6" data-testid="main-content">
        {children}
      </main>
    </div>
  );
}

client/src/components/layout/sidebar.tsx.content:
import { useAuth } from "@/hooks/use-auth";
import { useLanguage } from "@/components/language-provider";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { useLocation } from "wouter";
import { useQuery } from "@tanstack/react-query";
import {
  Home,
  File,
  Plus,
  HelpCircle,
  BarChart3,
  Users,
  Settings,
  ClipboardList,
  FileText,
  Scale,
  Building2,
} from "lucide-react";

interface SidebarProps {
  isOpen: boolean;
  onClose: () => void;
}

export function Sidebar({ isOpen, onClose }: SidebarProps) {
  const { user } = useAuth();
  const { t } = useLanguage();
  const [location, setLocation] = useLocation();

  const { data: stats } = useQuery({
    queryKey: ["/api/dashboard/stats"],
  });

  const navigate = (path: string) => {
    setLocation(path);
    onClose(); // Close sidebar on mobile after navigation
  };

  const isActive = (path: string) => {
    if (path === "/" && location === "/") return true;
    if (path !== "/" && location.startsWith(path)) return true;
    return false;
  };

  const adminNavItems = [
    {
      label: t('nav.dashboard', 'Dashboard'),
      icon: Home,
      path: '/',
    },
    {
      label: t('nav.userManagement', 'User Management'),
      icon: Users,
      path: '/users',
    },
    {
      label: t('nav.tenders', 'All Tenders'),
      icon: File,
      path: '/tenders',
    },
    {
      label: t('nav.clarifications', 'Clarifications'),
      icon: HelpCircle,
      path: '/clarifications',
      badge: stats?.pendingClarifications,
    },
    {
      label: t('nav.auditLogs', 'Audit Logs'),
      icon: ClipboardList,
      path: '/audit',
    },
    {
      label: t('nav.systemSettings', 'System Settings'),
      icon: Settings,
      path: '/settings',
    },
  ];

  const procurementNavItems = [
    {
      label: t('nav.dashboard', 'Dashboard'),
      icon: Home,
      path: '/',
    },
    {
      label: t('nav.manageTenders', 'Manage Tenders'),
      icon: File,
      path: '/tenders',
    },
    {
      label: t('nav.createTender', 'Create Tender'),
      icon: Plus,
      path: '/create-tender',
    },
    {
      label: t('nav.clarifications', 'Clarifications'),
      icon: HelpCircle,
      path: '/clarifications',
      badge: stats?.pendingClarifications,
    },
    {
      label: t('nav.bidEvaluation', 'Bid Evaluation'),
      icon: Scale,
      path: '/evaluation',
    },
    {
      label: t('nav.reports', 'Reports'),
      icon: BarChart3,
      path: '/reports',
    },
  ];

  const bidderNavItems = [
    {
      label: t('nav.dashboard', 'Dashboard'),
      icon: Home,
      path: '/',
    },
    {
      label: t('nav.availableTenders', 'Available Tenders'),
      icon: FileText,
      path: '/tenders',
    },
    {
      label: t('nav.myBids', 'My Bids'),
      icon: File,
      path: '/my-bids',
    },
    {
      label: t('nav.askClarifications', 'Ask Clarifications'),
      icon: HelpCircle,
      path: '/clarifications',
    },
    {
      label: t('nav.companyProfile', 'Company Profile'),
      icon: Building2,
      path: '/profile',
    },
  ];

  const getNavItems = () => {
    switch (user?.role) {
      case 'admin':
        return adminNavItems;
      case 'procurement_officer':
        return procurementNavItems;
      case 'bidder':
        return bidderNavItems;
      default:
        return [];
    }
  };

  const getRoleTitle = () => {
    switch (user?.role) {
      case 'admin':
        return t('nav.administration', 'Administration');
      case 'procurement_officer':
        return t('nav.procurement', 'Procurement');
      case 'bidder':
        return t('nav.bidding', 'Bidding');
      default:
        return '';
    }
  };

  return (
    <>
      {/* Mobile overlay */}
      {isOpen && (
        <div
          className="lg:hidden fixed inset-0 bg-black/50 z-30"
          onClick={onClose}
          data-testid="sidebar-overlay"
        />
      )}

      {/* Sidebar */}
      <aside
        className={cn(
          "sidebar",
          isOpen && "open"
        )}
        data-testid="sidebar"
      >
        <nav className="p-4 space-y-2">
          <div className="mb-6">
            <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">
              {getRoleTitle()}
            </h3>
          </div>

          {getNavItems().map((item) => {
            const Icon = item.icon;
            const active = isActive(item.path);

            return (
              <Button
                key={item.path}
                variant={active ? "secondary" : "ghost"}
                className={cn(
                  "w-full justify-start gap-3 h-10",
                  active && "bg-sidebar-accent font-medium text-sidebar-accent-foreground"
                )}
                onClick={() => navigate(item.path)}
                data-testid={`nav-${item.path.replace('/', '') || 'dashboard'}`}
              >
                <Icon className="w-4 h-4" />
                <span className="flex-1 text-left">{item.label}</span>
                {item.badge && item.badge > 0 && (
                  <Badge
                    variant="secondary"
                    className="ml-auto bg-primary text-primary-foreground text-xs px-2 py-1 rounded-full"
                    data-testid={`badge-${item.path.replace('/', '')}`}
                  >
                    {item.badge}
                  </Badge>
                )}
              </Button>
            );
          })}
        </nav>
      </aside>
    </>
  );
}

client/src/components/ui/alert-dialog.ts.content:
import * as React from "react"
import * as AlertDialogPrimitive from "@radix-ui/react-alert-dialog"

import { cn } from "@/lib/utils"
